document.addEventListener("DOMContentLoaded",function(){const e=Array.from(document.querySelectorAll(".post-content h2, .post-content h3")),t=Array.from(document.querySelectorAll(".toc #TableOfContents a"));if(!e.length||!t.length)return;function n(){let n=null;for(let t=e.length-1;t>=0;t--){const s=e[t].getBoundingClientRect();if(s.top<window.innerHeight*.3){n=e[t].id;break}}t.forEach(e=>{e.hash==="#"+n?(e.classList.add("active"),e.scrollIntoView({block:"nearest",behavior:"smooth"})):e.classList.remove("active")})}window.addEventListener("scroll",n,{passive:!0}),n()})